import{_ as a,a as r}from"./chunks/LaunchServer.BeAinQTL.js";import{_ as o,c as t,o as p,ae as s}from"./chunks/framework.DN7zo1cr.js";const i="/images/DeepSeekProxy.png",l="/images/cross_s1.png",n="/images/cross_s2.png",f=JSON.parse('{"title":"DeepSeekProxy","description":"","frontmatter":{},"headers":[],"relativePath":"home/DeepSeek.md","filePath":"home/DeepSeek.md"}'),c={name:"home/DeepSeek.md"};function _(m,e,h,k,d,P){return p(),t("div",null,e[0]||(e[0]=[s('<h1 id="deepseekproxy" tabindex="-1">DeepSeekProxy <a class="header-anchor" href="#deepseekproxy" aria-label="Permalink to &quot;DeepSeekProxy&quot;">​</a></h1><blockquote><p>✨在1.61以上的版本中，插件支持调用DeepSeek的API进行答案解析<br> 🔓在不使用DeepSeekProxy的情况下，每个用户每日有50次的限额<br> 🖥️如果想要无限制地调用，需要使用DeepSeekProxy</p></blockquote><h2 id="_1️⃣获取api-key" tabindex="-1">1️⃣获取API Key <a class="header-anchor" href="#_1️⃣获取api-key" aria-label="Permalink to &quot;1️⃣获取API Key&quot;">​</a></h2><p><a href="./GetAPIKey">点击查看教程</a></p><h2 id="_2️⃣下载并运行-ze网课助手-自建ai题库" tabindex="-1">2️⃣下载并运行 ZE网课助手（自建AI题库） <a class="header-anchor" href="#_2️⃣下载并运行-ze网课助手-自建ai题库" aria-label="Permalink to &quot;2️⃣下载并运行 ZE网课助手（自建AI题库）&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">提示</p><p>ZE网课助手（自建AI题库）是开源软件，不会上传用户的API Key。该软件用于开启DeepSeekProxy本地代理服务器</p></div><ul><li><a href="https://wwyl.lanzouv.com/b00ocrzzje" target="_blank" rel="noreferrer">蓝奏云</a> 密码：43so</li><li><a href="https://gitee.com/m0zey/ZjoocEasyPro/releases" target="_blank" rel="noreferrer">Gitee</a> 下载.zip文件</li><li><a href="https://dwpan.com/f/pYfY/ZE_qiestion_bank.zip" target="_blank" rel="noreferrer">直链下载</a></li></ul><h3 id="打开软件" tabindex="-1">打开软件 <a class="header-anchor" href="#打开软件" aria-label="Permalink to &quot;打开软件&quot;">​</a></h3><p><img src="'+a+'" alt="open_exe"></p><p>填入相应平台的API Key，然后点击保存，启动服务</p><p><img src="'+i+'" alt="images/DeepSeekProxy.png"></p><p><img src="'+r+'" alt="LaunchServer"></p><h2 id="_3️⃣为什么需要deepseekproxy" tabindex="-1">3️⃣为什么需要DeepSeekProxy？ <a class="header-anchor" href="#_3️⃣为什么需要deepseekproxy" aria-label="Permalink to &quot;3️⃣为什么需要DeepSeekProxy？&quot;">​</a></h2><p>因为目前所有的API都是不能跨域的，也就是说不能在一个网站中进行请求,所以需要搭建<code>代理服务器</code>。 <img src="'+l+'" alt="浏览器拦截"><img src="'+n+'" alt="浏览器拦截"></p><p>用户每日50次的非DeepSeekProxy调用使用的是我们服务器的资源，因此有限制。而使用DeepSeekProxy则相当于直接与大模型平台进行交互，完全不经过我们的服务器，不会对我们的服务器造成压力，所以没有限制。</p>',15)]))}const u=o(c,[["render",_]]);export{f as __pageData,u as default};
